final:
module binary_counter(
    input            clk  ,
    input            rstn ,

    output reg [3:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rstn or posedge dbg_halt)
begin
    if (!rstn)       count <= 0;
    else if (count == 4'b1111) count <= 0;
    else              count <= count + 1;
end

endmodule
